## paths.R
## Source this file at the top of every script with: source(here::here("paths.R"))
##
## Defines all data paths relative to the repository root using the here package,
## so scripts run without modification on any machine provided the data files are
## placed in the locations described below and in data/external/README.md.
##
## DATA FOLDER SUMMARY
## data/bundled/   - small open datasets committed to the repository
## data/external/  - datasets the user must download separately (gitignored)
## data/processed/ - intermediate outputs; some generated by R scripts, some by QGIS

library(here)

# ── Root directories ──────────────────────────────────────────────────────────

PATH_BUNDLED   <- here("data", "bundled")
PATH_EXTERNAL  <- here("data", "external")
PATH_PROCESSED <- here("data", "processed")


# ╔══════════════════════════════════════════════════════════════════════════════
# ║  BUNDLED DATA  (committed to the repository)
# ╚══════════════════════════════════════════════════════════════════════════════

# WFD River Basin Districts shapefile
# Source: DATA.GOV.UK
# Used in: bio_data_prep.R, env_data_prep.R
PATH_WFD_BASINS <- file.path(PATH_BUNDLED, "WFD_River_Basin_Districts_Cycle_2.shp")

# WFD River Water Body Catchments shapefile
# Source: DATA.GOV.UK
# Used in: env_data_prep.R
PATH_WFD_CATCHMENTS <- file.path(PATH_BUNDLED, "WFD_River_Water_Body_Catchments_Cycle_2.shp")

# WFD water body classifications — HMWB and artificial water body flags
# Source: https://data.catchmentbasedapproach.org/maps/4cff14f14acc41d2ac7c2a6b1e200c10
# Used in: future_pred_data_prep.R
PATH_WFD_CLASS <- file.path(PATH_BUNDLED, "WFD_River_Canal_SWT_FullClass16_Eng_identity_6260226168399521051.csv")

# Schedule 2 (D4 indicator) freshwater species list
# Source: Extracted from https://www.legislation.gov.uk/uksi/2023/91/made
